import{_ as e,o as i,c as o,a2 as r}from"./chunks/framework.C24VBsJ9.js";const s=JSON.parse('{"title":"GPIO 按键驱动（轮询）教程","description":"","frontmatter":{},"headers":[],"relativePath":"tutorial/driver/05_gpio_key_driver/index.md","filePath":"tutorial/driver/05_gpio_key_driver/index.md","lastUpdated":1779887266000}'),t={name:"tutorial/driver/05_gpio_key_driver/index.md"};function l(d,a,n,_,h,c){return i(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="gpio-按键驱动-轮询-教程" tabindex="-1">GPIO 按键驱动（轮询）教程 <a class="header-anchor" href="#gpio-按键驱动-轮询-教程" aria-label="Permalink to &quot;GPIO 按键驱动（轮询）教程&quot;">​</a></h1><p>前面的教程我们学习了 LED 和蜂鸣器驱动，这些都是 GPIO <strong>输出</strong>设备。现在我们进入 GPIO <strong>输入</strong>设备的世界——按键驱动。</p><h2 id="这个教程讲什么" tabindex="-1">这个教程讲什么 <a class="header-anchor" href="#这个教程讲什么" aria-label="Permalink to &quot;这个教程讲什么&quot;">​</a></h2><p>本教程讲解轮询式的 GPIO 按键驱动实现。虽然轮询方式效率不高，但代码简单直观，适合学习 GPIO 输入的基本原理。</p><div class="tip custom-block"><p class="custom-block-title">学习路径建议</p><p>建议按顺序阅读：</p><ol><li>先学本教程（轮询方式）——理解基本原理</li><li>再学中断消抖驱动——学习生产级的实现方式</li></ol><p>轮询 → 中断，由简入繁，学习效果更好。</p></div><h2 id="学习目标" tabindex="-1">学习目标 <a class="header-anchor" href="#学习目标" aria-label="Permalink to &quot;学习目标&quot;">​</a></h2><p>通过这个教程，你将会：</p><ul><li>理解 GPIO 输入机制和 Descriptor API</li><li>掌握轮询方式的实现原理和代码结构</li><li>了解按键抖动问题和简单的消抖方法</li><li>认识到轮询方式的局限性，为学习中断方式打基础</li></ul><h2 id="教程目录" tabindex="-1">教程目录 <a class="header-anchor" href="#教程目录" aria-label="Permalink to &quot;教程目录&quot;">​</a></h2><h3 id="_1-前言" tabindex="-1">1. <a href="./01_introduction">前言</a> <a class="header-anchor" href="#_1-前言" aria-label="Permalink to &quot;1. [前言](./01_introduction.md)&quot;">​</a></h3><p>从输出到输入，介绍输入设备的特殊性、按键驱动要解决的问题，以及为什么先学轮询方式。</p><h3 id="_2-gpio-输入机制" tabindex="-1">2. <a href="./02_gpio_input_mechanism">GPIO 输入机制</a> <a class="header-anchor" href="#_2-gpio-输入机制" aria-label="Permalink to &quot;2. [GPIO 输入机制](./02_gpio_input_mechanism.md)&quot;">​</a></h3><p>讲解如何配置 GPIO 为输入、如何读取状态、<code>GPIO_ACTIVE_LOW</code> 的作用，以及 <code>gpiod_get_value()</code> 的内部实现。</p><h3 id="_3-轮询实现" tabindex="-1">3. <a href="./03_polling_implementation">轮询实现</a> <a class="header-anchor" href="#_3-轮询实现" aria-label="Permalink to &quot;3. [轮询实现](./03_polling_implementation.md)&quot;">​</a></h3><p>深入分析 <code>read()</code> 函数的实现，讲解阻塞 I/O、<code>signal_pending()</code>、<code>copy_to_user()</code> 和 <code>schedule()</code> 的作用。</p><h3 id="_4-抖动现象" tabindex="-1">4. <a href="./04_bounce_phenomenon">抖动现象</a> <a class="header-anchor" href="#_4-抖动现象" aria-label="Permalink to &quot;4. [抖动现象](./04_bounce_phenomenon.md)&quot;">​</a></h3><p>分析机械按键抖动的物理原因、对轮询方式的影响，以及为什么轮询方式难以完美处理抖动。</p><h3 id="_5-编译和测试" tabindex="-1">5. <a href="./05_build_and_test">编译和测试</a> <a class="header-anchor" href="#_5-编译和测试" aria-label="Permalink to &quot;5. [编译和测试](./05_build_and_test.md)&quot;">​</a></h3><p>完整的编译部署流程、测试程序、调试技巧，以及轮询方式的性能对比。</p><h2 id="硬件要求" tabindex="-1">硬件要求 <a class="header-anchor" href="#硬件要求" aria-label="Permalink to &quot;硬件要求&quot;">​</a></h2><ul><li>Alpha 开发板（或兼容的 i.MX6ULL 开发板）</li><li>一个按键（板载或外接）</li></ul><h2 id="预备知识" tabindex="-1">预备知识 <a class="header-anchor" href="#预备知识" aria-label="Permalink to &quot;预备知识&quot;">​</a></h2><p>建议先完成这些教程：</p><ul><li><a href="./../03_platform_led_driver/">Platform LED 驱动</a>——了解 Platform 框架和 GPIO 输出</li><li><a href="./../04_beep_driver/">蜂鸣器驱动</a>——理解 GPIO 极性配置</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>从 <a href="./01_introduction">前言</a> 开始学习，或者直接跳到你感兴趣的章节。</p><p>学完本教程后，继续学习 <a href="./../06_debounced_key_driver/">中断消抖驱动</a>，了解更高效的输入驱动实现方式。</p>',27)])])}const u=e(t,[["render",l]]);export{s as __pageData,u as default};
